#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2026/1/21# @Author : cyq# @File : runner# @Software: PyCharm# @Desc:import asynciofrom typing import Union, Optionalfrom app.mapper.interfaceApi.interfaceMapper import InterfaceMapperfrom app.mapper.interfaceApi.interfaceCaseMapper import InterfaceCaseMapperfrom app.mapper.interfaceApi.interfaceGroupMapper import InterfaceGroupMapperfrom app.mapper.interfaceApi.interfaceVarsMapper import InterfaceVarsMapperfrom app.mapper.project.env import EnvMapperfrom croe.interface.executor.context import CaseStepContext, ExecutionContextfrom croe.interface.executor.interface_executor import InterfaceExecutorfrom croe.interface.executor.step_content import get_step_strategyfrom croe.a_manager import VariableManagerfrom croe.interface.writer import init_interface_case_result, write_case_result, write_interface_case_result, \    write_interface_resultfrom enums import InterfaceCaseErrorStepfrom croe.interface.starter import APIStarterfrom croe.play.starter import UIStarterfrom croe.interface.types import *from utils import logclass InterfaceRunner:    """接口入口"""    __slots__ = ("starter", "variable_manager", "interface_executor")    def __init__(self, starter: Union[UIStarter, APIStarter]):        self.starter = starter        self.variable_manager = VariableManager()        self.interface_executor = InterfaceExecutor(self.starter, self.variable_manager)    async def try_interface(self, interface_id: int, env_id: int) -> "InterfaceResultInfo":        """        执行单个接口请求调试        :param interface_id: 接口id        :param env_id: 环境id        :return: 接口执行结果        """        interface = await InterfaceMapper.get_by_id(ident=interface_id)        env = await EnvMapper.get_by_id(ident=env_id)        result, _ = await self.interface_executor.execute(interface=interface, env=env)        log.debug(result)        return result    async def try_group(self, group_id: int, env_id: int):        """        执行接口组        :param group_id 组ID        :param env_id  环境ID        """        interfaces = await InterfaceGroupMapper.query_apis(groupId=group_id)        env = await EnvMapper.get_by_id(env_id)        results = []        for interface in interfaces:            await self.starter.send(f"✍️✍️  Execute    {interface}")            result, _ = await self.interface_executor.execute(interface=interface, env=env)            results.append(result)        return results    async def run_interface_case(self, interface_case_id: int, env: Union["Env", int], error_stop: bool,                                 task_result: Optional["InterfaceTaskResult"] = None):        """        执行接口业务流 用例        :param interface_case_id: 接口用例id        :param env: 环境id 或者对象        :param error_stop: 是否遇到错误停止执行        :param task_result: 在任务中执行时，需要传递任务执行结果        :return: 接口执行结果        """        interface_case = await InterfaceCaseMapper.get_by_id(ident=interface_case_id)        log.info(f"查询到业务流用例  {interface_case}")        if not interface_case:            await self.starter.send(f"未通过{interface_case_id} 找到 相关业务流用例")            return await self.starter.over()        # 待执行的 case content 步骤        case_content_steps = await InterfaceCaseMapper.query_content(case_id=interface_case.id)        await self.starter.send(f"用例 {interface_case.title} 执行开始。执行人 {self.starter.username}")        await self.starter.send(f"查询到关联Step x {len(case_content_steps)} ...")        if not case_content_steps:            await self.starter.send("无可执行业务流步骤，结束执行")            return await self.starter.over()        #   初始化 业务流前置变量        await self.init_interface_case_vars(interface_case_id)        #   解析环境        if isinstance(env, int):            target_env = await EnvMapper.get_by_id(ident=env)        else:            target_env = env        await self.starter.send(f"✍️✍️ 使用环境 {target_env}")        # 默认结果为成功        CASE_SUCCESS = True        # 初始化 业务流结果对象        case_result = await init_interface_case_result(            starter=self.starter,            interface_case=interface_case,            env=target_env,            task_result=task_result        )        try:            context = ExecutionContext(                interface_case=interface_case,                env=target_env,                case_result=case_result,                task_result=task_result            )            for index, step_content in enumerate(case_content_steps, start=1):                await self.starter.send(                    f"✍️✍️ {'=' * 20} EXECUTE_STEP {index} ： {step_content} {'=' * 20}"                )                case_result.progress = round(index / len(case_content_steps), 2) * 100                # 步骤开关 用例调试中使用 任务执行默认开启                if step_content.enable == 0 and not task_result:                    await self.starter.send(f"✍️✍️  EXECUTE_STEP {index} ： 调试禁用 跳过执行")                    continue                # 如果 flag 已经是 False 且需要错误停止，则跳过后续步骤                if not CASE_SUCCESS and error_stop:                    await self.starter.send(f"⏭️⏭️  SKIP_STEP {index} ： 遇到错误已停止")                    continue                step_context = CaseStepContext(                    index=index,                    content=step_content,                    execution_context=context,                    starter=self.starter,                    variable_manager=self.variable_manager,                )                strategy = get_step_strategy(step_content.content_type, self.interface_executor)                step_success = await strategy.execute(step_context)                CASE_SUCCESS &= step_success                if not CASE_SUCCESS and interface_case.error_stop == InterfaceCaseErrorStep.STOP:                    case_result.progress = 100                    break                log.debug(f"case_result ===== {case_result}")                await write_case_result(case_result=case_result)                await self.starter.send(f"\n")            await self.starter.send(f"用例 {interface_case.title} 执行结束")            await self.starter.send(f"{'====' * 20}")            case_result.interfaceLog = "".join(self.starter.logs)            await write_interface_case_result(case_result=case_result)            return CASE_SUCCESS, case_result        except Exception as e:            log.exception(e)            return False, case_result        finally:            await self.variable_manager.clear()            await self.starter.over(case_result.id)    async def run_interface_by_task(self, interface: "InterfaceAPI",                                    task_result: "InterfaceTaskResult",                                    retry: int = 0,                                    retry_interval: int = 0,                                    env: "Env" = None):        """        执行接口任务        :param interface: 接口对象        :param task_result: 接口任务结果对象        :param retry: 重试次数        :param retry_interval: 重试间隔        :param env: 环境对象        :return:        """        for attempt in range(retry + 1):            result, success = await self.interface_executor.execute(interface=interface, task_result=task_result,                                                                    env=env)            # 成功则记录结果并返回            if success:                await write_interface_result(**result)                return True            # 最后一次重试失败，记录结果并返回False            if attempt == retry:                await write_interface_result(**result)                await self.starter.send(f"接口 {interface} 执行结果 FALSE")                return False            # 进行重试            await self.starter.send(f"接口 {interface} 执行结果 FALSE 第 {attempt + 1} 次重试")            if retry_interval:                await asyncio.sleep(retry_interval)    async def init_interface_case_vars(self, interface_case_id: int):        """        初始化业务流用例变量        :param interface_case_id: 业务流用例id        :return:        """        try:            interfaceCaseVars = await InterfaceVarsMapper.query_by(case_id=interface_case_id)            if interfaceCaseVars:                var_dict = {}                for _var in interfaceCaseVars:                    var_dict[_var.key] = await self.variable_manager.trans(_var.value)                await self.variable_manager.add_vars(var_dict)                await self.starter.send(f"🫳🫳 初始化业务用例变量 = {self.variable_manager.variables}")        except Exception as e:            log.error(e)